        # Split by , or ;
        parts = re.split(r'[,;]+', val)
        for p in parts:
            p = p.strip().lower()
            if '@' in p and p:
                emails.add(p)

print(f'Total unique emails: {len(emails)}')
sorted_emails = sorted(emails)
for e in sorted_emails[:10]:
    print(e)
"

