const fs = require("fs");
const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  Header, Footer, AlignmentType, LevelFormat, HeadingLevel, BorderStyle,
  WidthType, ShadingType, PageNumber, PageBreak, TabStopType, TabStopPosition
} = require("docx");

// ─── Helpers ───

const CONTENT_W = 9360; // US Letter - 1" margins
const noBorder = { style: BorderStyle.NONE, size: 0 };
const noBorders = { top: noBorder, bottom: noBorder, left: noBorder, right: noBorder };
const thinBorder = { style: BorderStyle.SINGLE, size: 1, color: "CCCCCC" };
const thinBorders = { top: thinBorder, bottom: thinBorder, left: thinBorder, right: thinBorder };

const heading = (level, text) =>
  new Paragraph({ heading: level, children: [new TextRun(text)] });

const para = (text, opts = {}) =>
  new Paragraph({
    spacing: { after: 120 },
    ...opts,
    children: typeof text === "string" ? [new TextRun(text)] : text,
  });

const bold = (text) => new TextRun({ text, bold: true });
const normal = (text) => new TextRun(text);
const italic = (text) => new TextRun({ text, italics: true });
const code = (text) => new TextRun({ text, font: "Courier New", size: 20 });

const spacer = () => new Paragraph({ spacing: { after: 80 }, children: [] });

// Bullet / number references
const bulletRef = "ob-bullets";
const numberRef = "ob-numbers";

const bullet = (text, level = 0) =>
  new Paragraph({
    numbering: { reference: bulletRef, level },
    spacing: { after: 60 },
    children: typeof text === "string" ? [new TextRun(text)] : text,
  });

const numbered = (text, level = 0, ref = numberRef) =>
  new Paragraph({
    numbering: { reference: ref, level },
    spacing: { after: 60 },
    children: typeof text === "string" ? [new TextRun(text)] : text,
  });

const tableRow = (cells, header = false) =>
  new TableRow({
    children: cells.map((c, i) =>
      new TableCell({
        borders: thinBorders,
        width: { size: c.width, type: WidthType.DXA },
        shading: header ? { fill: "1A1A2E", type: ShadingType.CLEAR } : undefined,
        margins: { top: 60, bottom: 60, left: 100, right: 100 },
        children: [
          new Paragraph({
            children: [
              new TextRun({
                text: c.text,
                bold: header,
                color: header ? "FFFFFF" : "333333",
                font: "Arial",
                size: 20,
              }),
            ],
          }),
        ],
      })
    ),
  });

const makeTable = (headers, rows, widths) =>
  new Table({
    width: { size: CONTENT_W, type: WidthType.DXA },
    columnWidths: widths,
    rows: [
      tableRow(headers.map((h, i) => ({ text: h, width: widths[i] })), true),
      ...rows.map((row) =>
        tableRow(row.map((t, i) => ({ text: t, width: widths[i] })))
      ),
    ],
  });

// ─── Document ───

const doc = new Document({
  styles: {
    default: {
      document: { run: { font: "Arial", size: 22, color: "222222" } },
    },
    paragraphStyles: [
      {
        id: "Heading1", name: "Heading 1", basedOn: "Normal", next: "Normal", quickFormat: true,
        run: { size: 36, bold: true, font: "Arial", color: "1A1A2E" },
        paragraph: { spacing: { before: 360, after: 200 }, outlineLevel: 0 },
      },
      {
        id: "Heading2", name: "Heading 2", basedOn: "Normal", next: "Normal", quickFormat: true,
        run: { size: 28, bold: true, font: "Arial", color: "2D2D5E" },
        paragraph: { spacing: { before: 280, after: 160 }, outlineLevel: 1 },
      },
      {
        id: "Heading3", name: "Heading 3", basedOn: "Normal", next: "Normal", quickFormat: true,
        run: { size: 24, bold: true, font: "Arial", color: "444477" },
        paragraph: { spacing: { before: 200, after: 120 }, outlineLevel: 2 },
      },
    ],
  },
  numbering: {
    config: [
      {
        reference: bulletRef,
        levels: [
          { level: 0, format: LevelFormat.BULLET, text: "\u2022", alignment: AlignmentType.LEFT,
            style: { paragraph: { indent: { left: 720, hanging: 360 } } } },
          { level: 1, format: LevelFormat.BULLET, text: "\u25E6", alignment: AlignmentType.LEFT,
            style: { paragraph: { indent: { left: 1440, hanging: 360 } } } },
        ],
      },
      {
        reference: numberRef,
        levels: [
          { level: 0, format: LevelFormat.DECIMAL, text: "%1.", alignment: AlignmentType.LEFT,
            style: { paragraph: { indent: { left: 720, hanging: 360 } } } },
        ],
      },
      {
        reference: "phase-numbers",
        levels: [
          { level: 0, format: LevelFormat.DECIMAL, text: "%1.", alignment: AlignmentType.LEFT,
            style: { paragraph: { indent: { left: 720, hanging: 360 } } } },
        ],
      },
    ],
  },
  sections: [
    // ════════════════════════════════════════════════
    // COVER PAGE
    // ════════════════════════════════════════════════
    {
      properties: {
        page: {
          size: { width: 12240, height: 15840 },
          margin: { top: 1440, right: 1440, bottom: 1440, left: 1440 },
        },
      },
