          border: { bottom: { style: BorderStyle.SINGLE, size: 4, color: "1A1A2E", space: 12 } },
          children: [],
        }),
        spacer(),
        new Paragraph({
          alignment: AlignmentType.CENTER,
          spacing: { after: 80 },
          children: [new TextRun({ text: "Implementation Plan", size: 32, bold: true, color: "2D2D5E" })],
        }),
        new Paragraph({
          alignment: AlignmentType.CENTER,
          spacing: { after: 40 },
          children: [new TextRun({ text: "Version 1.0  \u2014  March 2026", size: 22, color: "777777" })],
        }),
        spacer(), spacer(), spacer(), spacer(), spacer(), spacer(), spacer(), spacer(),
        new Paragraph({
          alignment: AlignmentType.CENTER,
          children: [new TextRun({ text: "Stack: Python (FastAPI) \u00B7 PostgreSQL + pgvector \u00B7 Docker \u00B7 Claude Haiku", size: 20, color: "999999" })],
        }),
        new Paragraph({ children: [new PageBreak()] }),
      ],
    },

    // ════════════════════════════════════════════════
    // MAIN CONTENT
    // ════════════════════════════════════════════════
    {
      properties: {
        page: {
          size: { width: 12240, height: 15840 },
          margin: { top: 1440, right: 1440, bottom: 1440, left: 1440 },
        },
      },
      headers: {
        default: new Header({
          children: [
            new Paragraph({
              children: [
                new TextRun({ text: "Open Brain \u2014 Implementation Plan", size: 18, color: "999999", font: "Arial" }),
