          children: [
            new Paragraph({
              alignment: AlignmentType.CENTER,
              children: [
                new TextRun({ text: "Page ", size: 18, color: "999999" }),
                new TextRun({ children: [PageNumber.CURRENT], size: 18, color: "999999" }),
              ],
            }),
          ],
        }),
      },
      children: [
        // ── 1. EXECUTIVE SUMMARY ──
        heading(HeadingLevel.HEADING_1, "1. Executive Summary"),
        para("Open Brain is a personal AI-readable knowledge system that captures thoughts, decisions, and context into a structured PostgreSQL database. It combines raw storage with LLM-powered refinement to create a durable, searchable second brain."),
        para("This plan covers the full implementation from database schema through CLI tool, organized into four phases over approximately 6 weeks."),

        // ── 2. TECH STACK ──
        heading(HeadingLevel.HEADING_1, "2. Technology Stack"),
        spacer(),
        makeTable(
          ["Component", "Technology", "Rationale"],
          [
            ["API Framework", "Python 3.12 + FastAPI", "Async, type-safe, minimal boilerplate"],
            ["Database", "PostgreSQL 16 + pgvector", "Single DB for relational + vector data"],
            ["LLM (Refinement)", "Claude 3.5 Haiku (Anthropic API)", "Cost-effective structured extraction"],
            ["Embeddings", "OpenAI text-embedding-3-small", "1536 dims, ~$0.02/1M tokens"],
            ["Queue", "PostgreSQL (pg_notify + polling)", "No extra infra for MVP"],
            ["Containerization", "Docker Compose", "Reproducible VPS deployment"],
            ["CLI", "Python (click or typer)", "Reuses API client code"],
          ],
          [2200, 3200, 3960]
        ),

        // ── 3. DATABASE SCHEMA ──
        heading(HeadingLevel.HEADING_1, "3. Database Schema"),

        heading(HeadingLevel.HEADING_2, "3.1 raw_memory"),
        para("Immutable store for all ingested content. Nothing is ever deleted from this table."),
        spacer(),
        makeTable(
          ["Column", "Type", "Notes"],
          [
            ["id", "uuid (PK, default gen_random_uuid())", ""],
            ["source", "text NOT NULL", "cli, api, slack, manual"],
            ["raw_text", "text NOT NULL", "Original verbatim content"],
            ["author", "text NOT NULL", "User identifier"],
            ["metadata", "jsonb DEFAULT '{}'", "Source-specific context"],
            ["created_at", "timestamptz DEFAULT now()", "Ingestion timestamp"],
          ],
          [2000, 4200, 3160]
        ),

        heading(HeadingLevel.HEADING_2, "3.2 memory_items"),
        para("Refined, structured knowledge derived from raw memory. Supports append-only with superseding chains for corrections."),
        spacer(),
        makeTable(
          ["Column", "Type", "Notes"],
          [
            ["id", "uuid (PK)", ""],
            ["raw_id", "uuid FK \u2192 raw_memory", "Link to source"],
            ["type", "text NOT NULL", "note | task | decision | meeting | idea | correction | weekly_report"],
            ["content", "text NOT NULL", "Normalized full text"],
            ["summary", "text", "LLM-generated summary"],
            ["base_importance", "float DEFAULT 0.3", "Set at ingestion (0.0\u20131.0)"],
            ["dynamic_importance", "float DEFAULT 0.0", "Recalculated daily"],
            ["importance_score", "float GENERATED ALWAYS AS (0.6 * base_importance + 0.4 * dynamic_importance)", "Composite score"],
            ["embedding", "vector(1536)", "From normalized text"],
            ["supersedes_memory_id", "uuid FK \u2192 memory_items (nullable)", "Correction chain"],
            ["is_superseded", "boolean DEFAULT false", "True if a newer entry supersedes this one"],
            ["created_at", "timestamptz DEFAULT now()", ""],
          ],
          [2000, 4200, 3160]
        ),

        heading(HeadingLevel.HEADING_2, "3.3 entities"),
        spacer(),
        makeTable(
          ["Column", "Type", "Notes"],
          [
            ["id", "uuid (PK)", ""],
            ["name", "text NOT NULL UNIQUE", "Canonical normalized name"],
            ["type", "text NOT NULL", "person | project | concept | tool | org"],
            ["created_at", "timestamptz DEFAULT now()", ""],
          ],
          [2000, 4200, 3160]
        ),

        heading(HeadingLevel.HEADING_2, "3.4 entity_aliases"),
        para("Maps variant names to canonical entities for resolution."),
        spacer(),
        makeTable(
          ["Column", "Type", "Notes"],
          [
            ["id", "uuid (PK)", ""],
            ["alias", "text NOT NULL UNIQUE", "Variant (e.g. \"me\", \"P.\")"],
            ["entity_id", "uuid FK \u2192 entities", "Canonical entity"],
            ["source", "text DEFAULT 'auto'", "auto | manual"],
          ],
          [2000, 4200, 3160]
        ),

        heading(HeadingLevel.HEADING_2, "3.5 entity_relations"),
        spacer(),
        makeTable(
          ["Column", "Type", "Notes"],
          [
            ["from_entity", "uuid FK \u2192 entities", ""],
            ["to_entity", "uuid FK \u2192 entities", ""],
            ["relation_type", "text NOT NULL", "works_on | owns | related_to | decided_by"],
            ["memory_id", "uuid FK \u2192 memory_items", "Source memory item"],
          ],
          [2200, 3500, 3660]
        ),

        heading(HeadingLevel.HEADING_2, "3.6 memory_entity_links"),
        para("Many-to-many junction between memory items and entities."),
        spacer(),
        makeTable(
          ["Column", "Type", "Notes"],
          [
            ["memory_id", "uuid FK \u2192 memory_items", ""],
            ["entity_id", "uuid FK \u2192 entities", ""],
          ],
          [3000, 3500, 2860]
        ),

        heading(HeadingLevel.HEADING_2, "3.7 decisions"),
        spacer(),
        makeTable(
          ["Column", "Type", "Notes"],
          [
            ["id", "uuid (PK)", ""],
            ["memory_id", "uuid FK \u2192 memory_items", ""],
            ["decision", "text NOT NULL", "What was decided"],
            ["reasoning", "text", "Why"],
            ["alternatives", "jsonb DEFAULT '[]'", "Other options considered"],
          ],
          [2000, 4200, 3160]
        ),

        heading(HeadingLevel.HEADING_2, "3.8 tasks"),
        spacer(),
        makeTable(
          ["Column", "Type", "Notes"],
          [
            ["id", "uuid (PK)", ""],
            ["memory_id", "uuid FK \u2192 memory_items", ""],
            ["description", "text NOT NULL", ""],
            ["owner", "text", ""],
            ["due_date", "timestamptz", ""],
            ["status", "text DEFAULT 'open'", "open | in_progress | done"],
          ],
          [2000, 4200, 3160]
        ),

        heading(HeadingLevel.HEADING_2, "3.9 failed_refinements (Dead Letter Queue)"),
        spacer(),
        makeTable(
          ["Column", "Type", "Notes"],
          [
            ["id", "uuid (PK)", ""],
            ["raw_id", "uuid FK \u2192 raw_memory", "Source that failed"],
            ["error_reason", "text NOT NULL", "What went wrong"],
            ["attempt_count", "int DEFAULT 1", "Max 3 before dead-lettering"],
            ["last_output", "jsonb", "Last LLM response for debugging"],
            ["created_at", "timestamptz DEFAULT now()", ""],
            ["resolved_at", "timestamptz", "When manually resolved"],
          ],
          [2000, 4200, 3160]
        ),

        heading(HeadingLevel.HEADING_2, "3.10 refinement_queue"),
        para("Postgres-backed job queue for async pipeline processing."),
        spacer(),
        makeTable(
          ["Column", "Type", "Notes"],
          [
            ["id", "uuid (PK)", ""],
            ["raw_id", "uuid FK \u2192 raw_memory", ""],
            ["status", "text DEFAULT 'pending'", "pending | processing | done | failed"],
            ["attempts", "int DEFAULT 0", ""],
            ["locked_at", "timestamptz", "Worker lock"],
            ["created_at", "timestamptz DEFAULT now()", ""],
          ],
          [2000, 4200, 3160]
        ),

        heading(HeadingLevel.HEADING_2, "3.11 Indexes"),
        bullet("HNSW index on memory_items.embedding (vector_cosine_ops)"),
        bullet("GIN index on memory_items.content for full-text search (to_tsvector)"),
        bullet("B-tree on memory_items.type, memory_items.created_at"),
        bullet("B-tree on entities.name, entity_aliases.alias"),
        bullet("B-tree on tasks.status, tasks.due_date"),
        bullet("B-tree on refinement_queue.status"),

        new Paragraph({ children: [new PageBreak()] }),

        // ── 4. REFINEMENT PIPELINE ──
        heading(HeadingLevel.HEADING_1, "4. Refinement Pipeline"),

        heading(HeadingLevel.HEADING_2, "4.1 Pipeline Flow"),
        para("All ingestion is asynchronous. The API writes to raw_memory + refinement_queue, then returns immediately. A background worker processes the queue."),
        spacer(),
        para([
          code("POST /memory \u2192 raw_memory + refinement_queue"),
        ]),
        para([
          code("Worker picks job \u2192 Normalize \u2192 Extract \u2192 Validate \u2192 Embed \u2192 Store"),
        ]),

        heading(HeadingLevel.HEADING_2, "4.2 Stage 1: Text Normalization"),
        bullet("Strip transcription artifacts, fix obvious typos"),
        bullet("Split entries longer than ~2000 tokens into logical chunks"),
        bullet("Lightweight \u2014 can be rule-based, no LLM needed"),

        heading(HeadingLevel.HEADING_2, "4.3 Stage 2: Structured Extraction (Claude Haiku)"),
        para("Single LLM call with structured JSON output. The prompt requests:"),
        bullet("summary (1\u20132 sentences)"),
        bullet("type classification (note | task | decision | meeting | idea)"),
        bullet("entities with name + type"),
        bullet("tasks with description, owner, due_date"),
        bullet("decisions with reasoning and alternatives"),
        bullet("base_importance score (0.0\u20131.0) based on content signals"),

        heading(HeadingLevel.HEADING_2, "4.4 Stage 3: Validation"),
        bullet("JSON schema validation (jsonschema library)"),
        bullet("Required field checks"),
        bullet("Entity name normalization (lowercase, trim, fuzzy match against existing entities)"),

        heading(HeadingLevel.HEADING_2, "4.5 Stage 4: Embedding Generation"),
        bullet("Generate embedding from normalized text via OpenAI text-embedding-3-small"),
        bullet("Store as vector(1536) in memory_items"),

        heading(HeadingLevel.HEADING_2, "4.6 Failure Handling"),
        para("Three-attempt retry strategy:"),
        numbered("Attempt 1: Standard extraction prompt"),
        numbered("Attempt 2: Stricter prompt with explicit schema enforcement"),
        numbered("Attempt 3: Repair prompt analyzing previous failed output"),
        para("After 3 failures, the entry moves to failed_refinements with error_reason and last_output for manual review or periodic reprocessing."),

        new Paragraph({ children: [new PageBreak()] }),

        // ── 5. RETRIEVAL ENGINE ──
        heading(HeadingLevel.HEADING_1, "5. Retrieval Engine"),

        heading(HeadingLevel.HEADING_2, "5.1 Hybrid Search"),
        para("Every search query runs three parallel retrieval paths:"),
        numbered("Vector search \u2014 cosine similarity on query embedding vs memory_items.embedding"),
        numbered("Keyword search \u2014 PostgreSQL full-text search (ts_rank) on memory_items.content"),
        numbered("Structured filters \u2014 type, entity, date range, task status"),

        heading(HeadingLevel.HEADING_2, "5.2 Ranking Formula"),
        spacer(),
        makeTable(
          ["Signal", "Weight", "Source"],
          [
            ["Semantic similarity", "0.50", "pgvector cosine distance"],
            ["Keyword match", "0.20", "ts_rank score (normalized)"],
            ["Importance score", "0.20", "Composite from base + dynamic"],
            ["Recency", "0.10", "Exponential decay from created_at"],
          ],
          [3000, 1500, 4860]
        ),
        spacer(),
        para("Superseded entries are excluded from results unless explicitly requested (audit mode)."),

        heading(HeadingLevel.HEADING_2, "5.3 Context Window Builder"),
        para("The retrieval engine does not return raw results. A context builder layer assembles a focused context package for downstream LLM consumption:"),
        bullet("Selects top-N results (configurable, default 10)"),
        bullet("Prioritizes decisions and tasks over notes"),
        bullet("Truncates long entries to summary + key excerpts"),
        bullet("Attaches relevant entity context"),
        bullet("Returns structured JSON ready for LLM system prompts"),

        // ── 6. IMPORTANCE SCORING ──
        heading(HeadingLevel.HEADING_1, "6. Importance Scoring"),

        heading(HeadingLevel.HEADING_2, "6.1 Base Importance (Set at Ingestion)"),
        bullet("Contains decision: +0.3"),
        bullet("Contains task: +0.2"),
        bullet("Long/detailed entry: +0.1"),
        bullet("Default baseline: 0.3"),

        heading(HeadingLevel.HEADING_2, "6.2 Dynamic Importance (Daily Recalculation)"),
        bullet("Retrieval frequency: normalized count of times retrieved in search results"),
        bullet("Reference count: number of other memory items linking to this entry"),
        bullet("Entity centrality: importance of linked entities (entities appearing in many memories score higher)"),

        heading(HeadingLevel.HEADING_2, "6.3 Composite Formula"),
        para([code("importance_score = 0.6 * base_importance + 0.4 * dynamic_importance")]),
        para("Implemented as a PostgreSQL generated column for zero-cost reads."),

        new Paragraph({ children: [new PageBreak()] }),

        // ── 7. API ENDPOINTS ──
        heading(HeadingLevel.HEADING_1, "7. API Endpoints"),
        spacer(),
        makeTable(
          ["Method", "Path", "Description"],
          [
            ["POST", "/memory", "Ingest raw memory (text + optional metadata)"],
            ["GET", "/search", "Hybrid search with query, filters, limit"],
            ["GET", "/search/context", "Search + context window builder output"],
            ["GET", "/memory/{id}", "Get single memory item with entity links"],
            ["GET", "/entity/{id}", "Get entity with aliases and related memories"],
            ["GET", "/entities", "List all entities (with optional type filter)"],
            ["POST", "/entity/{id}/alias", "Add alias to entity"],
            ["POST", "/entity/merge", "Merge two entities"],
            ["GET", "/tasks", "List tasks (filterable by status, owner, due)"],
            ["PATCH", "/tasks/{id}", "Update task status"],
            ["GET", "/decisions", "List decisions (filterable by date)"],
            ["GET", "/queue/status", "Refinement queue health"],
            ["GET", "/dead-letters", "Failed refinements for review"],
            ["POST", "/dead-letters/{id}/retry", "Reprocess a dead letter entry"],
          ],
          [1200, 3200, 4960]
        ),

        // ── 8. CLI TOOL ──
        heading(HeadingLevel.HEADING_1, "8. CLI Tool"),
        para("Lightweight Python CLI (using typer) that wraps the REST API."),
        spacer(),
        makeTable(
          ["Command", "Example", "Action"],
          [
            ["ob add", 'ob add "Decided to use pgvector"', "Ingest free-text memory"],
            ["ob task", "ob task \"Write API\" --owner petras --due 2026-03-20", "Create task entry"],
            ["ob decision", 'ob decision "Use Haiku for extraction"', "Create decision entry"],
            ["ob search", 'ob search "database choice"', "Search memories"],
            ["ob tasks", "ob tasks --status open", "List tasks"],
            ["ob entities", "ob entities --type project", "List entities"],
            ["ob status", "ob status", "Queue + dead letter health"],
          ],
          [1800, 4200, 3360]
        ),
        spacer(),
        para("The CLI sends all input to POST /memory. The LLM handles structuring \u2014 the CLI is intentionally dumb."),

