        para([code("\u2502   \u2502   \u251C\u2500\u2500 embedder.py      # OpenAI embedding calls")]),
        para([code("\u2502   \u2502   \u2514\u2500\u2500 entity_resolver.py")]),
        para([code("\u2502   \u251C\u2500\u2500 retrieval/")]),
        para([code("\u2502   \u2502   \u251C\u2500\u2500 search.py        # Hybrid search engine")]),
        para([code("\u2502   \u2502   \u251C\u2500\u2500 ranking.py       # Score combination")]),
        para([code("\u2502   \u2502   \u2514\u2500\u2500 context_builder.py")]),
        para([code("\u2502   \u251C\u2500\u2500 jobs/")]),
        para([code("\u2502   \u2502   \u251C\u2500\u2500 importance.py    # Daily recalculation")]),
        para([code("\u2502   \u2502   \u2514\u2500\u2500 synthesis.py     # Weekly report")]),
        para([code("\u2502   \u2514\u2500\u2500 llm/")]),
        para([code("\u2502       \u251C\u2500\u2500 client.py        # Anthropic API wrapper")]),
        para([code("\u2502       \u2514\u2500\u2500 prompts.py       # All LLM prompts")]),
        para([code("\u251C\u2500\u2500 cli/")]),
        para([code("\u2502   \u2514\u2500\u2500 ob.py                # Typer CLI app")]),
        para([code("\u2514\u2500\u2500 tests/")]),

        new Paragraph({ children: [new PageBreak()] }),

        // ── 14. KEY DESIGN DECISIONS ──
        heading(HeadingLevel.HEADING_1, "14. Key Design Decisions"),

        heading(HeadingLevel.HEADING_2, "D1: Postgres Queue over Redis/RabbitMQ"),
        para("For a single-user system processing ~50 entries/day, a Postgres-based queue (SELECT FOR UPDATE SKIP LOCKED) eliminates an entire infrastructure dependency. Can migrate to Redis later if throughput demands it."),

        heading(HeadingLevel.HEADING_2, "D2: Separate Embedding + LLM Providers"),
        para("Claude Haiku for structured extraction (strong instruction following, good JSON output). OpenAI text-embedding-3-small for embeddings (cheapest high-quality option, well-supported by pgvector). This avoids vendor lock-in on either side."),

        heading(HeadingLevel.HEADING_2, "D3: Generated Column for Importance Score"),
        para("The composite importance_score is a PostgreSQL generated column (0.6 * base + 0.4 * dynamic). This means reads are zero-cost and the formula is enforced at the database level, not in application code."),

        heading(HeadingLevel.HEADING_2, "D4: Superseding Chains over Mutations"),
        para("Instead of updating memory items (which violates append-only), corrections create new entries with supersedes_memory_id pointing to the original. Retrieval excludes superseded entries by default. Full audit trail preserved."),

        heading(HeadingLevel.HEADING_2, "D5: Context Builder as Separate Layer"),
        para("Raw search results are not useful to downstream LLMs. The context builder transforms ranked results into a structured context package with summaries, entity context, and token budget management. This is the interface between retrieval and AI consumption."),

