            ["Entity duplication", "Medium", "pg_trgm fuzzy matching + alias table + manual merge API"],
            ["Embedding model deprecation", "Medium", "Abstracted behind embedder.py; re-embed script for migration"],
            ["VPS single point of failure", "Medium", "Daily pg_dump backups to external storage"],
            ["Retrieval noise at scale", "Low (for 1\u20132yr)", "Hybrid ranking + HNSW index + importance weighting"],
            ["API key exposure", "High", "Environment variables only, .env excluded from git, API key auth on endpoints"],
          ],
          [3000, 1200, 5160]
        ),

        // ── 16. FUTURE EXTENSIONS ──
        heading(HeadingLevel.HEADING_1, "16. Future Extensions (Post-MVP)"),
        bullet("MCP adapter \u2014 expose Open Brain as an MCP server for Claude Code / other AI tools"),
        bullet("Slack ingestion bot \u2014 automatic capture from selected channels"),
        bullet("Browser extension \u2014 capture highlights and notes from web pages"),
        bullet("Knowledge graph visualization \u2014 entity relationship explorer UI"),
        bullet("Agent write proposals \u2014 AI suggests memory entries, human approves"),
        bullet("Cross-device mobile capture \u2014 lightweight PWA or Telegram bot"),

        spacer(), spacer(),
        new Paragraph({
          border: { top: { style: BorderStyle.SINGLE, size: 2, color: "1A1A2E", space: 8 } },
          spacing: { before: 200 },
          alignment: AlignmentType.CENTER,
          children: [new TextRun({ text: "End of Implementation Plan", size: 20, color: "999999", italics: true })],
        }),
      ],
    },
  ],
});

Packer.toBuffer(doc).then((buffer) => {
  fs.writeFileSync("/mnt/user-data/outputs/open-brain-implementation-plan.docx", buffer);
  console.log("Done: open-brain-implementation-plan.docx");
});

