const noBorders = { top: noBorder, bottom: noBorder, left: noBorder, right: noBorder };
const thinBorder = { style: BorderStyle.SINGLE, size: 1, color: "CCCCCC" };
const thinBorders = { top: thinBorder, bottom: thinBorder, left: thinBorder, right: thinBorder };

const heading = (level, text) =>
  new Paragraph({ heading: level, children: [new TextRun(text)] });

const para = (text, opts = {}) =>
  new Paragraph({
    spacing: { after: 120 },
    ...opts,
    children: typeof text === "string" ? [new TextRun(text)] : text,
  });

const bold = (text) => new TextRun({ text, bold: true });
const normal = (text) => new TextRun(text);
const italic = (text) => new TextRun({ text, italics: true });
const code = (text) => new TextRun({ text, font: "Courier New", size: 20 });

const spacer = () => new Paragraph({ spacing: { after: 80 }, children: [] });

// Bullet / number references
const bulletRef = "ob-bullets";
const numberRef = "ob-numbers";

const bullet = (text, level = 0) =>
  new Paragraph({
    numbering: { reference: bulletRef, level },
    spacing: { after: 60 },
    children: typeof text === "string" ? [new TextRun(text)] : text,
  });

const numbered = (text, level = 0, ref = numberRef) =>
  new Paragraph({
    numbering: { reference: ref, level },
    spacing: { after: 60 },
    children: typeof text === "string" ? [new TextRun(text)] : text,
  });

const tableRow = (cells, header = false) =>
  new TableRow({
    children: cells.map((c, i) =>
      new TableCell({
        borders: thinBorders,
        width: { size: c.width, type: WidthType.DXA },
        shading: header ? { fill: "1A1A2E", type: ShadingType.CLEAR } : undefined,
        margins: { top: 60, bottom: 60, left: 100, right: 100 },
        children: [
          new Paragraph({
            children: [
              new TextRun({
                text: c.text,
                bold: header,
                color: header ? "FFFFFF" : "333333",
                font: "Arial",
                size: 20,
              }),
            ],
          }),
        ],
      })
    ),
  });

const makeTable = (headers, rows, widths) =>
  new Table({
    width: { size: CONTENT_W, type: WidthType.DXA },
    columnWidths: widths,
    rows: [
      tableRow(headers.map((h, i) => ({ text: h, width: widths[i] })), true),
      ...rows.map((row) =>
        tableRow(row.map((t, i) => ({ text: t, width: widths[i] })))
