    );

    // ── SECTION 4: Leg/Keleiviu grouping ──
    Clear(_LegTasksWithGroupIndex);
    ClearCollect(
        _LegGroupingConfigForCycle,
        { CurrentGroupID: 1, NewGroupKeleiviu: true, NewGroupLeg: true }
    );
    ForAll(
        colIndexedTasks As IndexedTask,
        With(
            {
                _cfg: First(_LegGroupingConfigForCycle),
                _prev: LookUp(colIndexedTasks, RowIndex = IndexedTask.RowIndex - 1)
            },
