{"language": "markdown", "code": "from datetime import datetime

CALENDAR_STATE_SCHEMA = {
    "required": ["fetched_at", "date", "events"],
    "events_required": ["title", "start", "end", "all_day"],
}

NEWS_STATE_SCHEMA = {
    "required": ["fetched_at", "items", "errors"],
    "items_required": ["title", "source", "url", "summary", "topic", "published"],
}

def validate_state(data: dict, schema: dict) -> list[str]:
    """Return list of validation errors. Empty = valid."""
    errors = []
    for field in schema["required"]:
        if field not in data:
            errors.append(f"missing required field: {field}")
    # validate nested items
    items_key = next((k for k in schema if k.endswith("_required")), None)
    if items_key:
        collection = items_key.replace("_required", "")
        for i, item in enumerate(data.get(collection, [])):
            for field in schema[items_key]:
                if field not in item:
                    errors.append(f"{collection}[{i}] missing: {field}")
    return errors
