```python
# tests/test_schemas.py
import json
import pytest
from schemas import validate_state, CALENDAR_STATE_SCHEMA, NEWS_STATE_SCHEMA

def test_valid_calendar_state():
    with open("tests/fixtures/calendar_state.json") as f:
        data = json.load(f)
    assert validate_state(data, CALENDAR_STATE_SCHEMA) == []

def test_malformed_state_caught():
    with open("tests/fixtures/malformed_state.json") as f:
        data = json.load(f)
    errors = validate_state(data, CALENDAR_STATE_SCHEMA)
    assert len(errors) > 0

def test_empty_events_is_valid():
    """No events today is valid — not an error."""
    with open("tests/fixtures/empty_state.json") as f:
        data = json.load(f)
    assert validate_state(data, CALENDAR_STATE_SCHEMA) == []
```

**Where it runs:** `build_context.py` validates every state file before processing. Invalid state = skip that module + log error. Tests verify the validator catches known-bad inputs.

### Layer 2: Context Builder Tests

The context builder is deterministic — given the same input, it must produce the same output. This is the most testable and most important layer.

```python
# tests/test_context_builder.py
import pytest
from build_context import (
    build_calendar_context,
    build_news_context,
    build_tasks_context,
    merge_contexts,
)

class TestCalendarContext:
    def test_basic_event_formatting(self, sample_calendar_state):
        result = build_calendar_context(sample_calendar_state)
        assert "09:00–09:30" in result
        assert "Team standup" in result

    def test_tomorrow_preview_included(self, sample_calendar_state):
        result = build_calendar_context(sample_calendar_state)
        assert "Tomorrow" in result
        assert "Dentist" in result

    def test_empty_calendar(self):
        state = {"date": "2025-06-15", "events": [], "tomorrow_preview": []}
        result = build_calendar_context(state)
        assert "No events" in result

    def test_all_day_event_formatting(self):
        state = {
            "date": "2025-06-15",
            "events": [{"title": "Holiday", "start": "2025-06-15",
                        "end": "2025-06-15", "all_day": True}],
            "tomorrow_preview": []
        }
        result = build_calendar_context(state)
        assert "All day" in result

class TestNewsContext:
    def test_items_sorted_by_relevance(self, sample_news_state):
        result = build_news_context(sample_news_state)
        lines = [l for l in result.split("\n") if l.startswith("- ")]
        # highest relevance item should appear first
        assert "Anthropic" in lines[0]

    def test_truncation_at_token_budget(self):
        """If too many news items, lowest relevance gets cut."""
        bloated_state = make_news_state(item_count=50)
        result = build_news_context(bloated_state)
        assert len(result) < 3000  # rough char limit

    def test_empty_news(self):
        state = {"fetched_at": "2025-06-15T06:00:00Z", "items": [], "errors": []}
        result = build_news_context(state)
        assert "No news" in result or result.strip() == ""

class TestMergedContext:
    def test_all_sections_present(self, all_contexts):
        result = merge_contexts(all_contexts)
        assert "# Calendar" in result
        assert "# News" in result
        assert "# Tasks" in result
        assert "# Training" in result

    def test_frontmatter_has_date(self, all_contexts):
        result = merge_contexts(all_contexts)
        assert "date:" in result

    def test_missing_section_graceful(self):
        """If news context is None (fetch failed), other sections still work."""
        partial = {"calendar": "...", "news": None, "tasks": "...", "training": "..."}
        result = merge_contexts(partial)
        assert "# Calendar" in result
        assert "unavailable" in result.lower()  # should note missing section
```

### Layer 3: Fetcher Contract Tests

Fetchers hit external APIs, so unit tests mock the responses. The contract: whatever the source, the output must be a valid state file.

```python
