### Layer 4: Agent Output Validation

You can't unit-test AI output for correctness, but you can validate structure. This catches prompt regressions (agent stops producing valid markdown, forgets a section, etc.).

```python
# tests/test_agent_output.py
import re
import pytest

def parse_daily_note(content: str) -> dict:
    """Parse a generated daily note and return its structure."""
    sections = {}
    current = None
    for line in content.split("\n"):
        if line.startswith("## "):
            current = line[3:].strip().lower()
            sections[current] = []
        elif current:
            sections[current].append(line)
    return sections

class TestDailyNoteStructure:
    """Run against actual agent output saved as fixture."""

    @pytest.fixture
    def daily_note(self):
        # In CI: use a saved fixture
        # Locally: can test against real agent output
        with open("tests/fixtures/sample_daily_note.md") as f:
            return f.read()

    def test_has_required_sections(self, daily_note):
        sections = parse_daily_note(daily_note)
        for required in ["news", "schedule", "tasks"]:
            assert required in sections, f"Missing section: {required}"

    def test_has_frontmatter(self, daily_note):
        assert daily_note.startswith("---")
        assert "date:" in daily_note[:200]

    def test_tasks_have_checkboxes(self, daily_note):
        sections = parse_daily_note(daily_note)
        task_lines = [l for l in sections.get("tasks", []) if l.strip().startswith("- ")]
        for line in task_lines:
            assert "[ ]" in line or "[x]" in line

    def test_no_hallucinated_events(self, daily_note, sample_calendar_state):
        """Events in daily note should match calendar state input."""
        sections = parse_daily_note(daily_note)
        schedule = "\n".join(sections.get("schedule", []))
        for event in sample_calendar_state["events"]:
            assert event["title"] in schedule
